import { useCrmContext } from '../context/useCrmContext.js'

/**
 * Hook que expone las funciones de integración con Power Platform CRM
 */
export const useCRM = () => {
  const xrm = useCrmContext()

  /**
   * Retorna el userId del usuario actual sin llaves {}
   */
  const getUserIdNoBrackets = () => {
    try {
      return xrm.Utility.getGlobalContext()
        .userSettings.userId.replace('{', '')
        .replace('}', '')
    } catch {
      return ''
    }
  }

  /**
   * Retorna el entityId del formulario CRM activo sin llaves {}
   */
  const getEntityIdNoBrackets = () => {
    try {
      return xrm.LoadFormContext.getFormContext()
        .data.entity.getId()
        .replace('{', '')
        .replace('}', '')
    } catch {
      return ''
    }
  }

  /**
   * Retorna el valor de un atributo del formulario CRM
   */
  const getEntityAttributeValue = (attributeName) => {
    try {
      return xrm.LoadFormContext.getFormContext().getAttribute(attributeName).getValue()
    } catch {
      return ''
    }
  }

  /**
   * Retorna el objeto Xrm completo
   */
  const getXrm = () => xrm

  return { getUserIdNoBrackets, getEntityIdNoBrackets, getEntityAttributeValue, getXrm }
}
